"use strict";

(function (window, document) {
  var shareConfig = {
    shareTitle: '分享标题',
    shareImage: window.location.origin + '/assets/img/postCover/share_cover.png',
    shareContent: '分享描述',
    shareUrl: window.location.href
  }; // 新浪微博、QQ、QQ空间分享

  document.getElementById('shareWeibo').addEventListener('click', function () {
    shareMethodObj.sharetosina(shareConfig.shareTitle, shareConfig.shareUrl, shareConfig.shareImage);
  });
  document.getElementById('shareQQ').addEventListener('click', function () {
    shareMethodObj.sharetoqq(shareConfig.shareTitle, shareConfig.shareUrl, shareConfig.shareImage);
  });
  document.getElementById('shareQQZone').addEventListener('click', function () {
    shareMethodObj.sharetoqqzone(shareConfig.shareTitle, shareConfig.shareUrl, shareConfig.shareImage, shareConfig.shareContent);
  });
})(window, document);